var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":" 사령관님, 보고 계신가요?","JPN":" 司令官、見ていますか？","ENG":"Are you watching, Commander?","TWN":"司令官在看著嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":" 눈보라가 불기 시작한 뒤부터 적들이 계속 물러서고 있어요! ","JPN":" 吹雪が吹き始めてから、敵が後退しています！ ","ENG":"The enemies are drawing back, ever since the snowstorm started.","TWN":"下起暴風雪後，敵人就在不斷撤退！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":" 그래. 한 순간도 놓치지 않으려고 하는 중이다.","JPN":" ああ、一瞬たりとも逃さないようにしている。","ENG":"Yes. I'm trying not to miss anything.","TWN":"嗯，現在發生的一切我一刻都不想錯過。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":" 저것이 구 관리국의 화력인가……. ","JPN":" あれが旧管理局の火力なのか…… ","ENG":"So this must be the power of the Old Administration...","TWN":"那就是舊管理局的戰力嗎……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":" 우리가 고전하던 상대를 지도에서 지워 버리는 수준이군.","JPN":" 私たちが苦戦していた相手をまるで消しているようだ。","ENG":"It's extinguished our feared enemies from the map, with ease.","TWN":"簡直就是可以把我們苦戰的對手從地圖上抹去的水準啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":" 아직…… 가야 할 길이 멀어.","JPN":" 私たちの……進むべき道のりはまだ遠いな。","ENG":"…We still have a far way to go.","TWN":"要走的路……還很長啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":" 아가씨, 이상합니다. 포격이 쏟아지는 방향에서 고준위 침식파 반응이 검출되고 있어요.","JPN":" お嬢様、おかしいです。砲撃が発射されている方向から高レベルの侵食派反応が検出されています。","ENG":"Miss Jia, this is strange. I'm detecting high-level Corruption Ray responses from the direction of fire.","TWN":"小姐，很奇怪。從炮擊的發射方向上檢測到高侵蝕波反應。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":" 그림자 중에서도 이례적인 수준이에요. 당장 함선들을 재배치하겠습니다.","JPN":" シャドウの中でも異例なレベルです。直ちに各艦船を再配置します。","ENG":"The level of anomaly is exceptional, even for Shadows. I will rearrange the ships immediately.","TWN":"在暗影中也是非常罕見的程度。我馬上重新佈署艦船。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":" 이런 심도에서 이례적인 수준이에요. 위험합니다.","JPN":" この深度でこれは異例です。危険です。","ENG":"At this depth, the level is extremely high. It is dangerous.","TWN":"在這樣的深度是非常罕見的程度，很危險。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":" 괜찮아요, 이진 언니. 저희를 도와 주러 기꺼이 오신 분이거든요.","JPN":" 大丈夫ですよ、ホノカさん。私たちを助けに来てくださったんです。","ENG":"It's okay, Jin. She's here to help us.","TWN":"沒關係，李珍姐。她是來幫助我們的人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":" 도와 주다니요……? 침식체가 말입니까?","JPN":" 助けるって……？　侵食体がですか？","ENG":"Help us...? A C.O.?","TWN":"來幫助我們……？侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":" 아무렴 어때! 여기서부터는 우리가 한 방 먹여 주자고!","JPN":" 何でもいい！　ここからは俺たちが一発食らわせてやる番だ！","ENG":"Who cares? Let's go and beat up those bastards!","TWN":"管他的！要開始反擊了，吃我一拳吧！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":" 자, 잠깐! 같이 가!","JPN":" ま、待って！　私も行くよ！","ENG":"W-wait! Take me with you!","TWN":"等，等等！我也一起！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":" 빌어먹을! 아군 쪽에서 들려오는 포성은 왜 이렇게 듣기 좋냐!","JPN":" チクショウ！　味方陣営から聞こえてくる砲声は何でこんなにもいい音なんだよ！","ENG":"Aw shucks, why does an ally's gunfire sound so damn good?!","TWN":"真該死！我方這邊傳來的炮聲為什麼聽起來這麼動聽呢！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":" 다들 달려! 구경만 하다가 나중에 분배도 못 받는다!","JPN":" みんな走れ！　ぼけっと見ているようじゃ分け前はもらえなくなるぞ！","ENG":"Run! You won't get anything if you just stand there!","TWN":"大家衝啊！光是看熱鬧的話，以後什麼都分不到！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":" 헉…… 허억…….","JPN":" はっ……はぁ……","ENG":"*Huff*... *Huff*...","TWN":"咳……咳咳……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":" 슬슬 결판이 난 것 같군.","JPN":" そろそろ決着のようだな。","ENG":"I see our fight is coming to an end.","TWN":"看來已經分出勝負了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":" 아가씨의 칼도 아까보다 가벼워졌던데. 지금이 바로 포기할 때라고.","JPN":" お嬢さんの剣捌きもさっきより軽くなってきている。今がちょうど諦め時だぞ。","ENG":"Your blade hits weaker than before. Now is a good time to give up, Missy.","TWN":"你的劍比剛才變輕了。現在是時候放棄了吧，小姐。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":" ……웃기지 마라.","JPN":" ……笑わせるな。","ENG":"...Don't make me laugh.","TWN":"……別說笑了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":" 내가 어떻게 살아갈지……","JPN":" 私がどう生きるか……","ENG":"How I live...","TWN":"我要如何活……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":" 어떤 최후를 맞이할지.","JPN":" どんな最期を迎えるか。","ENG":"How I die.","TWN":"我的結局如何。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":" 네 놈 따위가 정할 수 있는 문제가 아냐!!","JPN":" 貴様なんぞが決めることではない！！","ENG":"They are not for you to decide!","TWN":"不是你這種傢伙能決定的！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":" 돌격해라! 놈들에게 달라붙지 못하면 이대로 당할 수밖에 없다!","JPN":" 突撃しろ！　あいつらに接近できなければこのままやられてしまうだけだ！","ENG":"Charge! If we don't stop them, it'll be the end of us!","TWN":"攻擊！如果不能纏住那些傢伙，就只能這樣被動挨打！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_A","text":{"KOREA":" 틀렸습니다! 화망이 워낙 두터운 나머지……!","JPN":" ダメです！　火網があまりにも強固で……！","ENG":"It won't work, sir! Their fire net is too–","TWN":"完，完了！火力太猛了……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":" 크헉……!?","JPN":" くはっ……！？","ENG":"Krrgh...?!","TWN":"呃……！？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":" 증원은! 어떻게 된 거냐! 어째서 증원을 부를 수 없는 거야!","JPN":" 増援は！　どうなっている！　どうして増援が呼べないんだ！","ENG":"W-where's backup?! Why can't we call in more?!","TWN":"增援！怎麼回事！為什麼叫不了增援！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":" 구원자님……! 구원은, 우리를 구원해 주신다던 약속은……!","JPN":" 救世主様……！　救いは、私たちを助けてくださるという約束は……！","ENG":"Savior...! Salvation, where the promised salvation–!","TWN":"救贖者大人……！我們的救贖在哪裡……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 저것이…… 현자가 감춰 둔 마지막 패인가?","JPN":" あれが……賢者が隠し持っていた最後のカードなのか？","ENG":"That... must be the wild card that the Sage kept hidden.","TWN":"那是……智者藏起來的最後一張牌嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 하지만 아무리 현자라도, 저런 괴물을 함부로 풀어 놓았다간……","JPN":" しかし、いくら賢者でも、あのような化け物を無闇に野放しにしては……","ENG":"But even for the Sage, letting loose a monster like that...","TWN":"不過就算是智者，釋放出那種怪物之後……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":" 버밍엄 교수님!","JPN":" バーミンガム教授！","ENG":"Professor Birmingham!","TWN":"伯明罕教授！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":" 아니, 알렌 버밍엄! 전황은 완전히 우리 측으로 넘어 왔다!","JPN":" いや、アレン・バーミンガム！　戦況は完全に私たちに傾いた！","ENG":"No, Allen Birmingham! The tides of war have clearly shifted towards our favor!","TWN":"不，艾倫·伯明罕！局勢完全偏向我們這邊了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":" 무기를 버리고 투항한다면 패자로서 예우해 주겠다!","JPN":" 武器を捨て投降すれば、敗者として配慮してやる！","ENG":"Abandon your weapons and surrender now, and you will be treated with respect as a defeated enemy!","TWN":"放下武器投降的話，我會以禮待之！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" ……좋은 제안을 거절해서 미안하군. 슈발리에 단장.","JPN":" ……良案を断ってしまい申し訳ない。シュヴァリエ団長。","ENG":"...I apologize for declining the generous offer, Captain Chevalier.","TWN":"……很抱歉拒絕你的這個提議，艾斯特洛索團長。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 하지만 내 마음은 처음부터 늘 같았다.","JPN":" 私の心は最初から決まっている。","ENG":"But my heart has always been the same.","TWN":"我的心意自始至終都沒變過。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 우리가 걸었던 길을 답습하기만 해 봤자, 그 끝은 정해져 있어.","JPN":" 我々がかつて歩んだを踏襲するだけでは、同じ結末を迎えてしまう。","ENG":"Repeating our past won't change anything.","TWN":"只要依循我們走過的路，結局就是註定的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 별의 인도자를, 우리를……","JPN":" 星の導く者を、我々を……","ENG":"Following the Star Guide, and us–","TWN":"就算追隨星之引導者，我們也……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 컥!","JPN":" かはっ！","ENG":"Krgh!","TWN":"咳！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":" 염동력……?","JPN":" 念動力……？","ENG":"Telekinesis...?","TWN":"這是念力……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":" 누구냐! 기사의 결투에 개입하는 자는!","JPN":" 誰だ！　騎士の決闘に横やりを入れる者は！","ENG":"Who dare interrupts a knight's battle!","TWN":"是誰！為什麼要介入騎士之間的決鬥！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 괴물이, 이 거리에서…….","JPN":" 怪物が、この距離で……","ENG":"The monster, trying to break my neck...","TWN":"那個怪物，是想在這個距離上……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 내 목을… 부러뜨릴 셈인가…!","JPN":" 私の首を……折る気か…！","ENG":"From that distance...!","TWN":"弄斷……我的脖子嗎……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":" 불필요한 희생을 낼 이유는 없다. 마왕의 사도.","JPN":" 不要な犠牲を出す必要はない。魔王の使徒。","ENG":"There is no need for unnecessary bloodshed, Apostle.","TWN":"沒有理由作出不必要的犧牲，魔王的使徒。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":" <color=#ffd34c>이곳</color>에서라면, 저격은 확실하다. ","JPN":" <color=#ffd34c>ここ</color>でなら、狙撃は確実だ。 ","ENG":"A clear shot is assured from <color=#ffd34c>here</color>.","TWN":"如果是在<color=#ffd34c>這個空間裡</color>，狙擊會很準確。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":" 적어도 옳은 결정을 했다고 느낄 수 있게, 도우려 했는데.","JPN":" 少なくとも、正しい決断をしたんだと君が思えるように、助けたかったんだが。","ENG":"I wanted you to feel that you've made the right choice, at least.","TWN":"我本想幫你，至少讓你覺得自己做了正確的決定。"},"stage":{"bg":"BLACK","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":" 마지막까지……. 친구인 너에게 짐만 남겼구나.","JPN":" 最後まで……友である君に背負わせてしまったな。","ENG":"Even in the last moment... I am leaving behind a burden to you, dear friend.","TWN":"結果到最後……還是對你造成了負擔，我的朋友。"},"stage":{"bg":"BLACK","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":" 고향이, 아니. 아카데미가.","JPN":" 故郷が、いや。アカデミーが。","ENG":"Our hometown, no, the academy...","TWN":"或許那個小鎮，不，學院。"},"stage":{"bg":"BLACK","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":" 너의 안식처였는데도.","JPN":" 君の安息の地だったのに。","ENG":"Was your sanctuary.","TWN":"才是你的避難之所。"},"stage":{"bg":"BLACK","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":" ……미안하다. 레이.","JPN":" ……許してくれ、レイ。","ENG":"...I'm sorry, Ray.","TWN":"……對不起，雷伊。"},"stage":{"bg":"BLACK","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":" 그만해! 멈춰!!","JPN":" やめろ！　やめろお！！","ENG":"Stop! I said stop!","TWN":"住手！停下！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};